// Préparer les données d'onboarding client
const data = $input.first().json.body || $input.first().json;

const client = data.client || {};
const facture = data.facture || {};

// Générer le slug client : prenom-secteur
const prenom = (client.nom || '').split(' ')[0].toLowerCase().replace(/[^a-z]/g, '');
const secteur = (client.secteur || 'web').toLowerCase().replace(/[^a-z]/g, '');
const slug = `${prenom}-${secteur}`;

// Templates secteur disponibles
const templateMap = {
  coiffure: 'template-coiffure',
  restaurant: 'template-restaurant',
  pizza: 'template-pizza',
  pizzeria: 'template-pizza',
  boutique: 'template-boutique',
  ecommerce: 'template-boutique',
  voiture: 'template-location-voiture'
};
const template = templateMap[secteur] || 'template-restaurant';

const dateOnboarding = new Date().toLocaleDateString('fr-FR', { timeZone: 'Indian/Reunion', day: '2-digit', month: 'long', year: 'numeric' });

return [{
  json: {
    slug,
    template,
    dateOnboarding,
    repoName: `client-${slug}`,
    repoUrl: `https://github.com/marrynov/client-${slug}`,
    sousDomaineDemo: `${secteur}.marrynov.re`,
    client: {
      nom: client.nom || 'Client',
      email: client.email,
      telephone: client.telephone,
      secteur: client.secteur || secteur
    },
    facture: {
      numero: facture.numero || 'N/A',
      montant: facture.montant || 0,
      date: facture.date || dateOnboarding
    }
  }
}];

